import{c as t,Q as i,j as s,m as a}from"./chunks/framework.BPKcPtvA.js";const h=JSON.parse('{"title":"How do I bulk-invite users from an Excel file?","description":"","frontmatter":{},"headers":[],"relativePath":"guide/recipes/portal/bulk-invite-users.md","filePath":"guide/recipes/portal/bulk-invite-users.md","lastUpdated":1778912818000}'),l={name:"guide/recipes/portal/bulk-invite-users.md"};function r(o,e,n,d,u,c){return i(),s("div",null,[...e[0]||(e[0]=[a('<h1 id="how-do-i-bulk-invite-users-from-an-excel-file" tabindex="-1">How do I bulk-invite users from an Excel file? <a class="header-anchor" href="#how-do-i-bulk-invite-users-from-an-excel-file" aria-label="Permalink to &quot;How do I bulk-invite users from an Excel file?&quot;">​</a></h1><div class="tip custom-block"><p class="custom-block-title">Who can do this</p><p><strong>Owner</strong> or <strong>Admin</strong></p></div><p>For 10+ invitees you can upload an Excel sheet instead of typing them in. We pre-fill names and roles from the spreadsheet so the review step is just a confirmation.</p><h2 id="steps" tabindex="-1">Steps <a class="header-anchor" href="#steps" aria-label="Permalink to &quot;Steps&quot;">​</a></h2><ol><li>Open <strong>Users</strong> in the sidebar.</li><li>Click <strong>Invite Users</strong> (top right).</li><li>In the <strong>Import from Excel</strong> panel, click <strong>Download Template</strong> and fill it in. Required column: email. Optional: first name, last name, role.</li><li>Click <strong>Import Excel</strong> and pick your filled-in file.</li><li>The emails populate in the left panel — duplicates and existing users are flagged.</li><li>Click <strong>Next</strong> to land on the review step. Fix anything the spreadsheet missed.</li><li>Click <strong>Send Invites</strong>.</li></ol><h2 id="result" tabindex="-1">Result <a class="header-anchor" href="#result" aria-label="Permalink to &quot;Result&quot;">​</a></h2><p>Each invitee gets an email with a verification link. The result modal shows successes and failures side by side — failures usually mean a malformed email or a user that already exists in another customer.</p><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="./invite-user">How do I invite a user to my customer?</a></li><li><a href="./bulk-assign-users">How do I bulk-assign users to a tenant?</a></li></ul>',9)])])}const m=t(l,[["render",r]]);export{h as __pageData,m as default};
